// 处理 RSS 数据
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  // 关键词过滤
  const mustHaveKeywords = ['创新药', 'ADC', '双抗', '细胞治疗', '基因治疗', 'AI制药', 'IND', 'NDA', '获批', 'License-out', '融资'];
  const excludeKeywords = ['招聘', '会议通知', '培训班', '广告'];

  const title = data.title || '';
  const content = data.content || data.description || '';
  const combinedText = title + ' ' + content;

  // 检查排除关键词
  const hasExclude = excludeKeywords.some(kw => combinedText.includes(kw));
  if (hasExclude) continue;

  // 检查必须关键词
  const hasMustHave = mustHaveKeywords.some(kw => combinedText.includes(kw));
  if (!hasMustHave) continue;

  // 论点标签
  const thesisTags = [];
  const thesisKeywords = {
    'clinical': ['临床试验', 'IND', '患者入组', 'CDE', '突破性疗法'],
    'discovery': ['靶点', 'First-in-class', '新模态', 'AI药物设计'],
    'engineering': ['CMC', '规模化生产', 'GMP', '质量控制'],
    'ai': ['AI制药', '深度学习', 'AlphaFold', '生成式AI']
  };

  for (const [tag, keywords] of Object.entries(thesisKeywords)) {
    if (keywords.some(kw => combinedText.includes(kw))) {
      thesisTags.push(tag);
    }
  }

  results.push({
    json: {
      id: data.link || data.guid || Date.now().toString(),
      title: title,
      url: data.link || '',
      source: '动脉网',
      published_at: data.pubDate || data.isoDate || new Date().toISOString(),
      collected_at: new Date().toISOString(),
      content: content.substring(0, 5000),
      thesis_tags: thesisTags,
      priority: thesisTags.length >= 2 ? 'high' : 'medium',
      status: 'pending'
    }
  });
}

return results.length > 0 ? results : [{ json: { no_results: true } }];

// 保存到本地文件
const items = $input.all();
const fs = require('fs');
const path = require('path');

const dataDir = '/home/node/.n8n/data';
if (!fs.existsSync(dataDir)) {
  fs.mkdirSync(dataDir, { recursive: true });
}

const today = new Date().toISOString().split('T')[0];
const filePath = path.join(dataDir, `news-${today}.json`);

let existingData = [];
if (fs.existsSync(filePath)) {
  existingData = JSON.parse(fs.readFileSync(filePath, 'utf8'));
}

const newData = items.map(item => item.json);
const existingUrls = new Set(existingData.map(d => d.url));

// 去重
const uniqueData = newData.filter(d => !existingUrls.has(d.url));
existingData.push(...uniqueData);

fs.writeFileSync(filePath, JSON.stringify(existingData, null, 2));

return [{ json: { saved: uniqueData.length, total: existingData.length, file: filePath } }];
